const money=(n:number)=>`RM${Number.isInteger(n)?n:n.toFixed(2)}`,count=()=>cart.reduce((s,i)=>s+i.qty,0),sub=()=>cart.reduce((s,i)=>s+i.price*i.qty,0),total=()=>sub()+D[ship].price,save=()=>localStorage.setItem('cart',JSON.stringify(cart));
function normalizeMalaysiaPhone(value:string){const digits=String(value||'').replace(/\D/g,'');const normalized=digits.startsWith('60')?digits:digits.startsWith('0')?'60'+digits.slice(1):digits.startsWith('1')?'60'+digits:'';return /^601\d{8,9}$/.test(normalized)?'+'+normalized:''}
function highlightDateNeed(){const row=document.querySelector<HTMLElement>('#dateNeedRow'),input=document.querySelector<HTMLInputElement>('#date');if(!row||!input)return;row.classList.remove('date-alert');void row.offsetWidth;row.classList.add('date-alert');row.scrollIntoView({behavior:'smooth',block:'center'});setTimeout(()=>{input.focus();try{input.showPicker()}catch{}},350)}
function edibleBase(size:string,style=''){let base=0;if(size==='A4'||size==='Cupcake')base=24;else if(size==='A5')base=12;else if(size==='A6')base=6;else{const n=parseFloat(size);base=n>=6?24:n>=4.5?12:6;if(style==='Square / Petak'&&size==='4 inch')base=12}return base}
function price(k:K,proc:string,size:string,style='',review='No Review'){if(k==='printed')return 10;if(k==='mirror')return proc==='Urgent'?18:15;if(k==='acrylic'){const b=size==='A7 Mini'?12:size==='A6 Standard'?20:35;if(proc!=='Urgent')return b;if(size==='A7 Mini')return 15;if(size==='A6 Standard')return 25;return 40}if(k==='burnaway'){if(size.includes('A4'))return 36;if(size.includes('A5'))return 18;const n=parseFloat(size);return n>=6?30:n>=5?18:12}if(k==='wafer'){const base=parseFloat(size)<=6?6:12;return base+(proc==='Urgent'&&review==='Need Review'?2:0)}const base=edibleBase(size,style);if(proc==='Urgent'&&review==='Need Review')return base===6?7:base===12?14:base===24?28:base;return base}
