function orderQuestionUrl(o:OrderRecord){const itemText=o.items.map((i,n)=>`${n+1}. ${i.qty}x ${i.title}${i.size?` (${i.size})`:''}`).join('\n'),msg=`Hi iCetak, saya nak tanya tentang order ini.\n\nOrder ID: ${o.id}\nDate Need: ${o.dateNeed}\nStatus: ${o.status}\nPayment: ${o.payment}\nDelivery: ${o.delivery}\n\nItem:\n${itemText}\n\nPertanyaan saya:`;return `https://wa.me/${WA}?text=${encodeURIComponent(msg)}`}
function navigate(next:Page,options:{replace?:boolean;product?:K;orderToken?:string}={}){if(page==='payment'&&next!=='payment')void unsubscribePayment();if(options.product)product=options.product;if(options.orderToken)selectedOrder=options.orderToken;page=next;const state={page,product,orderToken:selectedOrder};if(options.replace)history.replaceState(state,'',location.href);else history.pushState(state,'',location.href);render()}
