function burnawayVariant(now:boolean){const p=P.burnaway,shapes=['Round / Bulat','Square / Petak','Love Shape / Hati'],reviews=['No Review','Need Review'],edibleSizes=['3 inch','3.5 inch','4 inch','4.5 inch','5 inch','5.5 inch','6 inch','6.5 inch','7 inch','7.5 inch'],waferSizes=[...edibleSizes,'8 inch'];let shape=shapes[0],waferSize=waferSizes[0],edibleSize=edibleSizes[0],process=p.process[0],review=reviews[0],qty=1;const currentPrice=()=>{const ediblePrice=edibleBase(edibleSize,shape),waferCharge=parseFloat(waferSize)<=6?6:12;return ediblePrice+waferCharge+(process==='Urgent'?2:0)};const w=modal(`<button class="modal-x">×</button><div class="variant-head">${photo('burnaway')}<div><strong id="vprice">${money(currentPrice())}</strong><span>Stock tersedia</span></div></div><section class="variant-body"><h3>Process</h3>${opts('process',p.process,process)}${processNote}<h3>Review</h3>${opts('review',reviews,review)}<h3>Shape</h3>${opts('shape',shapes,shape)}<h3>🔥 Size Wafer Paper</h3>${opts('wafer',waferSizes,waferSize)}<h3>🎂 Size Edible Image Dalam</h3>${opts('edible',edibleSizes,edibleSize)}<div class="qty"><span>Quantity</span><div><button id="minus">−</button><b id="qty">1</b><button id="plus">+</button></div></div></section><button id="confirm" class="confirm">${now?'Buy Now':'Add to Cart'}</button>`);const paint=()=>{w.querySelector<HTMLElement>('#vprice')!.textContent=money(currentPrice());w.querySelector<HTMLElement>('#qty')!.textContent=String(qty);w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>{const v=b.dataset.g==='shape'?shape:b.dataset.g==='wafer'?waferSize:b.dataset.g==='edible'?edibleSize:b.dataset.g==='review'?review:process;b.classList.toggle('active',b.dataset.v===v)})};w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>b.onclick=()=>{if(b.dataset.g==='shape')shape=b.dataset.v!;if(b.dataset.g==='wafer')waferSize=b.dataset.v!;if(b.dataset.g==='edible')edibleSize=b.dataset.v!;if(b.dataset.g==='process')process=b.dataset.v!;if(b.dataset.g==='review')review=b.dataset.v!;paint()});w.querySelector<HTMLButtonElement>('#minus')!.onclick=()=>{qty=Math.max(1,qty-1);paint()};w.querySelector<HTMLButtonElement>('#plus')!.onclick=()=>{qty++;paint()};w.querySelector<HTMLButtonElement>('#confirm')!.onclick=()=>{const size=`Wafer ${waferSize} • Edible ${edibleSize}`,id=`burnaway|${shape}|${waferSize}|${edibleSize}|${process}|${review}`,f=cart.find(i=>i.id===id);if(f)f.qty+=qty;else cart.push({id,k:'burnaway',title:p.name,process,review,size,style:shape,price:currentPrice(),qty});save();w.remove();if(now)navigate('review');else{render();toast('Ditambah ke cart')}}}
