function variant(now:boolean){if(product==='burnaway'){burnawayVariant(now);return}if(product==='edible'||product==='wafer'){simpleFourVariant(now,product);return}if(product==='printed'){printedVariant(now);return}const p=P[product],reviews=['No Review','Need Review'];let process=p.process[0],review=reviews[0],size=p.size[0],style=p.style[0],qty=1;const w=modal(`<button class="modal-x">×</button><div class="variant-head">${photo(product)}<div><strong id="vprice">${money(price(product,process,size,style))}</strong><span>Stock tersedia</span></div></div><section class="variant-body"><h3>Process</h3>${opts('process',p.process,process)}${processNote}<h3>Review</h3>${opts('review',reviews,review)}<h3>Size</h3>${opts('size',p.size,size)}<h3>Shape / Color</h3>${opts('style',p.style,style)}<div class="qty"><span>Quantity</span><div><button id="minus">−</button><b id="qty">1</b><button id="plus">+</button></div></div></section><button id="confirm" class="confirm">${now?'Buy Now':'Add to Cart'}</button>`);const paint=()=>{const allowed=product==='edible'?edibleStyles(size):p.style;if(!allowed.includes(style))style=allowed[0];w.querySelector<HTMLElement>('#vprice')!.textContent=money(price(product,process,size,style));w.querySelector<HTMLElement>('#qty')!.textContent=String(qty);w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>{const v=b.dataset.g==='process'?process:b.dataset.g==='review'?review:b.dataset.g==='size'?size:style;const disabled=b.dataset.g==='style'&&!allowed.includes(b.dataset.v!);b.disabled=disabled;b.classList.toggle('disabled',disabled);b.classList.toggle('active',!disabled&&b.dataset.v===v)})};w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>b.onclick=()=>{if(b.dataset.g==='process')process=b.dataset.v!;if(b.dataset.g==='review')review=b.dataset.v!;if(b.dataset.g==='size')size=b.dataset.v!;if(b.dataset.g==='style'&&!b.disabled)style=b.dataset.v!;paint()});paint();w.querySelector<HTMLButtonElement>('#minus')!.onclick=()=>{qty=Math.max(1,qty-1);paint()};w.querySelector<HTMLButtonElement>('#plus')!.onclick=()=>{qty++;paint()};w.querySelector<HTMLButtonElement>('#confirm')!.onclick=()=>{const id=`${product}|${process}|${review}|${size}|${style}`,f=cart.find(i=>i.id===id);if(f)f.qty+=qty;else cart.push({id,k:product,title:p.name,process,review,size,style,price:price(product,process,size,style,review),qty});save();w.remove();if(now)navigate('review');else{render();toast('Ditambah ke cart')}}}
