async function cancelCustomerOrder(o:OrderRecord){const w=modal(`<button class="modal-x">×</button><h2>Cancel Order?</h2><p>Order belum dibayar. Anda boleh batalkan terus.</p><button id="confirmCancelOrder" class="confirm">Ya, Cancel Order</button><button id="keepOrder" class="confirm secondary-confirm">Kekalkan Order</button>`);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#keepOrder')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#confirmCancelOrder')!.onclick=async()=>{const b=w.querySelector<HTMLButtonElement>('#confirmCancelOrder')!;b.disabled=true;b.textContent='Cancelling…';try{await api.post('/api/orders/'+encodeURIComponent(o.orderToken)+'/cancel',{});w.remove();toast('Order cancelled');await loadOrder(o.orderToken)}catch{toast('Order tidak boleh dibatalkan');b.disabled=false;b.textContent='Ya, Cancel Order'}}}
function orderPage(){if(orderLoading||!currentOrder){root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Order Detail</h1></header><main class="order-detail-page"><div class="empty-history"><b>${orderLoading?'Loading order…':'Order tidak ditemui'}</b></div></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('history');return}const o=currentOrder,readyLabel=o.delivery==='Pickup'?'Ready':'Shipped',all=o.items.flatMap(i=>i.components||[]),stepsFor=(c:ProductionComponent)=>c.reviewRequired?['Order Received','Design Editing','Waiting Review','Approved','Production','Finishing',readyLabel]:['Order Received','Design Editing','Production','Finishing',readyLabel],stageIndex=(c:ProductionComponent)=>{const steps=stepsFor(c),workflow=c.workflow==='Ready to Pickup'?'Ready':c.workflow;const idx=steps.indexOf(workflow);return idx<0?0:idx},progresses=all.map(c=>stageIndex(c)/Math.max(1,stepsFor(c).length-1)),overall=Math.round((progresses.reduce((a,b)=>a+b,0)/Math.max(1,progresses.length))*100),waitingReview=all.filter(c=>c.reviewRequired&&c.workflow==='Waiting Review').length;root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Order Detail</h1></header><main class="order-detail-page"><section class="order-summary-card"><div><small>Order ID</small><div class="order-id-row"><h2>${o.id}</h2><button id="copyOrderRef" aria-label="Copy order ID and link">⧉</button></div><p>Date Need ${o.dateNeed}</p><div class="recipient-details"><b>${o.deliveryName||customer?.name||'Customer'}</b><span>${o.deliveryPhone||customer?.phone||''}</span><small>${o.delivery==='Pickup'?'📍':'🚚'} ${o.deliverySummary||o.delivery}</small></div></div><span class="status-pill ${o.status==='Action Required'?'alert':''}">${o.status}</span></section><section class="overall-progress"><div><b>Overall Progress</b><span>${overall}% • ${all.length} proses</span></div><div class="overall-bar"><i style="width:${overall}%"></i></div>${waitingReview?`<p>⚠️ ${waitingReview} design perlukan semakan dan approval anda.</p>`:''}</section><section class="compact-track-list"><div class="section-title"><b>Item & Production Tracking</b><button id="refreshOrder">↻ Refresh</button></div>${o.items.map((i,index)=>`<article class="item-production-card"><header><img src="${PRODUCT_IMAGES[i.k]}" alt="${i.title}"><div><small>Item ${index+1}</small><b>${i.qty}× ${i.title}</b><span>${i.size} • ${i.style}</span></div><strong>${money(i.price*i.qty)}</strong></header><div class="component-list">${(i.components||[]).map(c=>{const steps=stepsFor(c),current=stageIndex(c);return `<section class="component-track"><div class="component-head"><b>${c.label}</b><span>${c.workflow}</span></div><div class="horizontal-track" style="--steps:${steps.length}">${steps.map((s,n)=>`<div class="h-step ${n<current?'done':''} ${n===current?'current':''}"><i>${n<=current?'✓':''}</i><span>${s==='Order Received'?'Received':s==='Design Editing'?'Design':s==='Waiting Review'?'Review':s}</span></div>`).join('')}</div>${c.reviewRequired&&c.workflow==='Waiting Review'?`<div class="review-panel">${c.previewUrl?`<a href="${c.previewUrl}" target="_blank" rel="noopener">View ${c.label} Design</a><button data-approve-component="${c.id}" data-legacy="${c.legacy?'1':'0'}">Approve</button>`:'<span>Design belum dimuat naik oleh staff.</span>'}</div>`:''}</section>`}).join('')}</div></article>`).join('')}</section><section class="payment-box ${o.payment==='Paid'?'paid':''}"><b>Payment: ${o.payment}${o.payment==='Paid'?' ✅':''}</b><p>${o.payment==='Paid'?'Bayaran telah diterima.':o.payment==='Cash at Counter'?'Bayar semasa pickup di kaunter.':'Selesaikan bayaran untuk mula proses order.'}</p>${o.payment==='Unpaid'?'<button id="payOrderNow" class="pay-now-btn">Pay Now</button>':''}</section>${o.shipment?.tracking?`<section class="shipment-card"><div class="shipment-head"><div><small>${o.shipment.courier||o.delivery}</small><h3>${o.shipment.status||'Shipment Data Received'}</h3>${o.shipment.statusGroup?`<span>${o.shipment.statusGroup}</span>`:''}</div>${o.shipment.trackingLink?`<a href="${o.shipment.trackingLink}" target="_blank">Track Parcel</a>`:''}</div><button id="copyTracking" class="tracking-copy"><span>${o.shipment.tracking}</span><b>Copy</b></button>${o.shipment.events.length?`<div class="shipment-timeline">${o.shipment.events.map((e,n)=>`<article class="${n===0?'latest':''}"><i></i><div><b>${e.status}</b>${e.statusGroup?`<span>${e.statusGroup}</span>`:''}<small>${new Date(e.eventTime).toLocaleString('en-MY',{timeZone:'Asia/Kuala_Lumpur'})}</small></div></article>`).join('')}</div>`:''}</section>`:''}${o.canCancel?'<button id="cancelCustomerOrder" class="customer-cancel-btn">Cancel Order</button>':''}<div class="order-actions"><a href="${orderQuestionUrl(o)}">💬 Tanya Order Ini</a><button id="refreshBottom">↻ Refresh</button></div></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('history');const refresh=()=>void loadOrder(o.orderToken);document.querySelector<HTMLButtonElement>('#refreshOrder')!.onclick=refresh;document.querySelector<HTMLButtonElement>('#refreshBottom')!.onclick=refresh;document.querySelector<HTMLButtonElement>('#copyOrderRef')!.onclick=async()=>{await navigator.clipboard.writeText(`Order ID: ${o.id}\n${singleOrderUrl(o.orderToken)}`);toast('Order ID & link copied')};document.querySelector<HTMLButtonElement>('#payOrderNow')?.addEventListener('click',()=>{selectedOrder=o.orderToken;navigate('payment',{orderToken:o.orderToken});void loadPayment(o.orderToken)});document.querySelector<HTMLButtonElement>('#copyTracking')?.addEventListener('click',async()=>{await navigator.clipboard.writeText(o.shipment?.tracking||'');toast('Tracking copied')});document.querySelector<HTMLButtonElement>('#cancelCustomerOrder')?.addEventListener('click',()=>void cancelCustomerOrder(o));document.querySelectorAll<HTMLButtonElement>('[data-approve-component]').forEach(b=>b.onclick=async()=>{b.disabled=true;b.textContent='Approving…';const path=b.dataset.legacy==='1'?'/items/':'/components/';try{await api.post('/api/orders/'+encodeURIComponent(o.orderToken)+path+encodeURIComponent(b.dataset.approveComponent!)+'/approve',{});toast('Design approved');await loadOrder(o.orderToken)}catch{toast('Approval gagal');b.disabled=false;b.textContent='Approve'}})}
async function adminLogin(username:string,password:string){adminLoading=true;render();try{const r=await api.post('/api/admin/login',{username,password});adminSession=r.data.session_token;adminInfo={username:r.data.username,permissions:r.data.permissions};sessionStorage.setItem('admin_session',adminSession);await loadAdmin()}catch{adminLoading=false;adminSession='';sessionStorage.removeItem('admin_session');toast('Username atau password salah');render()}}
async function loadAdmin(){if(!adminSession)return;adminLoading=true;render();try{const r=await api.post('/api/admin/dashboard',{session_token:adminSession});adminInfo=r.data.admin;adminOrders=r.data.orders;adminUsers=r.data.admins}catch{adminSession='';adminInfo=null;sessionStorage.removeItem('admin_session');toast('Session admin tamat')}adminLoading=false;render()}
async function adminAction(orderDbId:string,action:string){try{await api.post('/api/admin/order-action',{session_token:adminSession,order_db_id:orderDbId,action});toast(action==='approve_production'?'Approved for production':'Order updated');await loadAdmin()}catch{toast(action==='approve_production'?'Customer belum confirm order':'Tindakan tidak dibenarkan')}}
function editAdminOrder(order:AdminOrder){const w=modal(`<button class="modal-x">×</button><h2>Edit ${order.id}</h2><form id="editAdminOrder" class="admin-edit-form"><label>Date Need<input type="date" name="date_need" value="${order.dateNeedRaw.slice(0,10)}" required></label><label>Admin Remark<textarea name="admin_remark" rows="3" placeholder="Contoh: tunggu artwork, customer hutang lama">${order.adminRemark||''}</textarea></label><h3>Items</h3>${order.items.map((i,n)=>`<fieldset data-edit-item="${i.id}"><legend>${n+1}. ${i.title}</legend><label>Qty<input name="qty_${i.id}" type="number" min="1" value="${i.qty}" required></label><label>Unit Price (RM)<input name="price_${i.id}" type="number" min="0" step="0.01" value="${i.price}" required></label><label>Custom Text<input name="text_${i.id}" value="${i.customText||''}"></label>${i.reviewRequired?`<label class="preview-url-field">Design Preview URL<input name="preview_${i.id}" type="url" placeholder="https://..." value="${i.previewUrl||''}"><small>Customer boleh buka design dan approve dalam app.</small></label>`:''}</fieldset>`).join('')}<button class="confirm">Save Changes</button></form>`);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLFormElement>('#editAdminOrder')!.onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),items=order.items.map(i=>({id:i.id,qty:Number(f.get(`qty_${i.id}`)),price:Number(f.get(`price_${i.id}`)),custom_text:String(f.get(`text_${i.id}`)||''),design_preview_url:String(f.get(`preview_${i.id}`)||'')}));try{await api.post('/api/admin/order-update',{session_token:adminSession,order_db_id:order.dbId,date_need:String(f.get('date_need')||''),admin_remark:String(f.get('admin_remark')||''),items});w.remove();toast('Order details saved');await loadAdmin()}catch{toast('Order update gagal')}}}
async function saveAdminPermissions(username:string){const permissions=Array.from(document.querySelectorAll<HTMLInputElement>(`[data-perm-user="${username}"]:checked`)).map(x=>x.value);try{await api.post('/api/admin/permissions',{session_token:adminSession,username,permissions});toast('Permission updated');await loadAdmin()}catch{toast('Permission gagal dikemas kini')}}
async function generatePaymentWebhookKey(){const button=document.querySelector<HTMLButtonElement>('#generateWebhookKey');if(button){button.disabled=true;button.textContent='Generating…'}try{const r=await api.post('/api/admin/payment-webhook-key',{session_token:adminSession}),key=String(r.data.key||'');const w=modal(`<button class="modal-x">×</button><h2>Payment Webhook Key</h2><p>Copy key ini sekarang. Ia tidak akan dipaparkan semula.</p><textarea id="webhookKeyValue" rows="4" readonly>${key}</textarea><button id="copyWebhookKey" class="confirm">Copy Webhook Key</button><p><b>Header:</b> x-webhook-key</p><p><b>Endpoint:</b> ${location.origin}/api/webhooks/payment-match</p>`);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#copyWebhookKey')!.onclick=async()=>{await navigator.clipboard.writeText(key);toast('Webhook key copied')};await loadAdmin()}catch{toast('Gagal jana webhook key');if(button){button.disabled=false;button.textContent='Generate Key'}}}
function downloadFile(name:string,content:string,type:string){const url=URL.createObjectURL(new Blob([content],{type})),a=document.createElement('a');a.href=url;a.download=name;a.click();URL.revokeObjectURL(url)}
async function exportAdminData(format:'json'|'csv'){try{const r=await api.post('/api/admin/export',{session_token:adminSession}),stamp=new Date().toISOString().slice(0,10);if(format==='json')downloadFile(`icetak-backup-${stamp}.json`,JSON.stringify(r.data,null,2),'application/json');else{const rows=(r.data.orders as Array<Record<string,unknown>>).map(o=>[o.order_id,o.created_at,o.date_need,o.total,o.payment,o.delivery,o.status,o.admin_status].map(v=>`"${String(v??'').replaceAll('"','""')}"`).join(','));downloadFile(`icetak-orders-${stamp}.csv`,['Order ID,Created,Date Need,Total,Payment,Delivery,Status,Admin Status',...rows].join('\n'),'text/csv')}toast('Backup downloaded')}catch{toast('Export gagal')}}
function singleOrderUrl(token:string){const u=new URL(location.href);['c','login','confirm','page'].forEach(k=>u.searchParams.delete(k));u.searchParams.set('order',token);return u.toString()}
function adminCreateOrder(){let rows=1;const row=(n:number)=>`<fieldset data-admin-new-item="${n}"><legend>Item ${n}</legend><label>Product<select name="k_${n}">${(Object.keys(P) as K[]).map(k=>`<option value="${k}">${P[k].name}</option>`).join('')}</select></label><label>Item Name<input name="title_${n}" placeholder="Contoh: Edible Image Didi" required></label><label>Qty<input name="qty_${n}" type="number" min="1" value="1" required></label><label>Unit Price RM<input name="price_${n}" type="number" min="0" step="0.01" required></label><label>Size<input name="size_${n}" placeholder="Contoh: 5 inch"></label><label>Shape / Color<input name="style_${n}" placeholder="Contoh: Round / Bulat"></label><label>Review<select name="review_${n}"><option>No Review</option><option>Need Review</option></select></label><label class="admin-wide">Custom Detail<input name="text_${n}" placeholder="Nama, umur, tema atau arahan"></label></fieldset>`;const w=modal(`<button class="modal-x">×</button><h2>Create Customer Order</h2><form id="adminCreateOrder" class="admin-create-order"><section><h3>Customer</h3><label>Name<input name="name" required></label><label>WhatsApp Malaysia<input name="phone" inputmode="tel" placeholder="0129554732" required></label><label>Date Need<input name="date_need" type="date" required></label><label>Delivery<select name="delivery"><option value="pickup">Pickup</option><option value="spx">SPX</option><option value="jnt">J&T</option><option value="ninja">Ninja Van</option></select></label><label>Payment<select name="payment"><option>Unpaid</option><option>Paid</option><option>Cash Counter</option></select></label><label class="admin-wide">Admin Remark<textarea name="admin_remark" rows="2"></textarea></label></section><section id="adminNewItems"><h3>Items</h3>${row(1)}</section><button type="button" id="addAdminItem" class="add-item-btn">+ Add Item</button><button class="confirm">Create & Prepare WhatsApp</button></form>`);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#addAdminItem')!.onclick=()=>{rows++;w.querySelector<HTMLElement>('#adminNewItems')!.insertAdjacentHTML('beforeend',row(rows))};w.querySelector<HTMLFormElement>('#adminCreateOrder')!.onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),phone=normalizeMalaysiaPhone(String(f.get('phone')||''));if(!phone){toast('Nombor WhatsApp Malaysia tidak sah');return}const items=[];for(let n=1;n<=rows;n++){const title=String(f.get(`title_${n}`)||'').trim();if(!title)continue;items.push({k:String(f.get(`k_${n}`)||'edible'),title,process:'Pre-order',review:String(f.get(`review_${n}`)||'No Review'),size:String(f.get(`size_${n}`)||''),style:String(f.get(`style_${n}`)||''),customText:String(f.get(`text_${n}`)||''),price:Number(f.get(`price_${n}`)||0),qty:Number(f.get(`qty_${n}`)||1)})}if(!items.length){toast('Tambah sekurang-kurangnya satu item');return}const btn=e.currentTarget.querySelector<HTMLButtonElement>('button[type="submit"],button.confirm')!;btn.disabled=true;btn.textContent='Creating…';try{const r=await api.post('/api/admin/orders',{session_token:adminSession,customer:{name:String(f.get('name')||''),phone,address_line1:'',city:'',postcode:'',state:'',phone_masked:'',address_masked:''},items,date_need:String(f.get('date_need')||''),delivery:String(f.get('delivery')||'pickup'),payment:String(f.get('payment')||'Unpaid'),admin_remark:String(f.get('admin_remark')||'')}),d=r.data as {order_id:string;order_token:string;confirm_token?:string;total:number};const link=d.confirm_token?`${location.origin}${location.pathname}?confirm=${encodeURIComponent(d.confirm_token)}`:singleOrderUrl(d.order_token),msg=`Hi ${String(f.get('name')||'')}, order iCetak anda telah direkodkan.\n\nOrder ID: ${d.order_id}\nDate Need: ${String(f.get('date_need')||'')}\nJumlah: ${money(d.total)}\n\nSemak${d.confirm_token?' dan sahkan':''} order di sini:\n${link}`;w.remove();const done=modal(`<button class="modal-x">×</button><h2>Order Created</h2><strong class="order-confirm-id">${d.order_id}</strong><p>Single order link sudah tersedia dan notification turut dimasukkan ke outbox untuk Activepieces.</p><a class="confirm wa-confirm" target="_blank" href="https://wa.me/${phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}">Send to Customer</a><button id="copyOrderLink" class="confirm secondary-confirm">Copy Order Link</button><button id="openCreatedOrder" class="confirm secondary-confirm">Open Order</button>`);done.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>done.remove();done.querySelector<HTMLButtonElement>('#copyOrderLink')!.onclick=async()=>{await navigator.clipboard.writeText(link);toast('Order link copied')};done.querySelector<HTMLButtonElement>('#openCreatedOrder')!.onclick=()=>{done.remove();selectedOrder=d.order_token;page='order';currentOrder=null;void loadOrder(selectedOrder)};await loadAdmin()}catch{toast('Order gagal dicipta');btn.disabled=false;btn.textContent='Create & Prepare WhatsApp'}}}
function adminPage(){if(!adminSession){root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Admin Login</h1></header><main class="admin-page"><section class="admin-login-card"><div class="admin-lock">🔐</div><h2>iCetak Order Control</h2><p>Login staff untuk monitor order dan semak bayaran.</p><form id="adminLoginForm"><label>Username<input name="username" autocomplete="username" required></label><label>Password<input name="password" type="password" autocomplete="current-password" required></label><button class="confirm">Login Admin</button></form></section></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>{page='catalog';render()};document.querySelector<HTMLFormElement>('#adminLoginForm')!.onsubmit=e=>{e.preventDefault();const f=new FormData(e.currentTarget);void adminLogin(String(f.get('username')||''),String(f.get('password')||''))};return}if(adminLoading&&!adminInfo){root.innerHTML='<main class="admin-page"><div class="empty-history"><b>Loading admin dashboard…</b></div></main>';return}const perms=adminInfo?.permissions||[],can=(p:string)=>perms.includes(p),tabs=[['all','All'],['new','New'],['pay','To Pay'],['cash','Cash Approval'],['ready','Ready'],['problem','Problem']],q=adminSearch.trim().toLowerCase(),filtered=adminOrders.filter(o=>(adminTab==='all'||adminTab==='new'&&o.adminStatus==='New Order'||adminTab==='pay'&&o.payment==='Unpaid'||adminTab==='cash'&&o.adminStatus==='Pending Cash Approval'||adminTab==='ready'&&o.adminStatus==='Ready to Process'||adminTab==='problem'&&['Cancelled','Action Required'].includes(o.adminStatus))&&(!q||[o.id,o.customerName,o.customerPhone].some(v=>v.toLowerCase().includes(q)))),customerOrders=selectedCustomerToken?adminOrders.filter(o=>o.customerToken===selectedCustomerToken):[],selectedCustomer=customerOrders[0];root.innerHTML=`<header class="admin-head"><div><small>Logged in as ${adminInfo?.username}</small><h1>Order Control Tower</h1></div><button id="adminLogout">Logout</button></header><main class="admin-page">${can('create_order')?'<button id="adminCreateOrderBtn" class="admin-create-order-btn">＋ Create Customer Order</button>':''}<section class="admin-metrics"><article><span>New</span><b>${adminOrders.filter(o=>o.adminStatus==='New Order').length}</b></article><article><span>To Pay</span><b>${adminOrders.filter(o=>o.payment==='Unpaid').length}</b></article><article><span>Cash Check</span><b>${adminOrders.filter(o=>o.adminStatus==='Pending Cash Approval').length}</b></article><article><span>Ready</span><b>${adminOrders.filter(o=>o.adminStatus==='Ready to Process').length}</b></article></section><form id="adminSearchForm" class="admin-search"><input name="search" value="${adminSearch}" placeholder="Search name, WhatsApp or Order ID"><button>Search</button>${adminSearch?'<button type="button" id="clearAdminSearch">Clear</button>':''}</form>${selectedCustomer?`<section class="customer-profile"><header><div><small>Customer Profile</small><h2>${selectedCustomer.customerName}</h2><a href="https://wa.me/${selectedCustomer.customerPhone}" target="_blank">${selectedCustomer.customerPhone}</a></div><button id="closeCustomerProfile">×</button></header><div class="customer-stats"><span><b>${customerOrders.length}</b> Orders</span><span><b>${money(customerOrders.reduce((s,o)=>s+o.total,0))}</b> Total</span><span><b>${money(customerOrders.filter(o=>o.payment==='Unpaid').reduce((s,o)=>s+o.total,0))}</b> Unpaid</span></div><div class="customer-order-history">${customerOrders.map(o=>`<button data-view-order="${o.orderToken}"><b>${o.id}</b><span>${o.created} • ${o.payment} • ${money(o.total)}</span></button>`).join('')}</div></section>`:''}<nav class="admin-tabs">${tabs.map(([k,l])=>`<button data-admin-tab="${k}" class="${adminTab===k?'active':''}">${l}</button>`).join('')}</nav><section class="admin-order-list">${filtered.length?filtered.map(o=>`<article class="admin-order-card"><header><div><b>${o.id}</b><small>${o.created} • Need ${o.dateNeed}</small></div><span>${o.adminStatus}</span></header><div class="admin-customer"><button data-customer-token="${o.customerToken}"><strong>${o.customerName}</strong><small>View all orders</small></button><a href="https://wa.me/${o.customerPhone}" target="_blank">${o.customerPhone||'No phone'}</a></div><div class="admin-order-meta"><span>${o.items.length} item</span><span>${o.payment}</span><span>${o.delivery}</span><b>${money(o.total)}</b></div><div class="admin-item-mini">${o.items.slice(0,3).map(i=>`<span>${i.qty}× ${i.title}</span>`).join('')}</div>${o.adminRemark?`<div class="admin-remark">📝 ${o.adminRemark}</div>`:''}${o.lastAction?`<small class="audit-line">Last: ${o.lastAction}</small>`:''}<footer><button data-view-order="${o.orderToken}">View</button>${can('edit_order')?`<button data-edit-order="${o.dbId}">Edit</button>`:''}${can('approve_production')&&!o.productionApproved&&o.payment!=='Unpaid'&&o.adminStatus!=='Cancelled'&&(o.payment!=='Cash at Counter'||o.customerConfirmed)?`<button class="primary" data-admin-action="approve_production" data-order-db="${o.dbId}">Approve Production</button>`:''}${o.payment==='Cash at Counter'&&!o.customerConfirmed?`<span class="confirm-lock">🔒 Tunggu customer confirm</span>`:''}${can('mark_paid')&&o.payment==='Unpaid'?`<button class="primary" data-admin-action="mark_paid" data-order-db="${o.dbId}">Confirm Payment</button>`:''}${can('approve_cash')&&o.adminStatus==='Pending Cash Approval'?`<button class="primary" data-admin-action="approve_cash" data-order-db="${o.dbId}">Approve Cash</button>`:''}${can('cancel_order')&&o.adminStatus!=='Cancelled'?`<button class="danger" data-admin-action="cancel" data-order-db="${o.dbId}">Cancel</button>`:''}</footer></article>`).join(''):'<div class="empty-history"><b>No matching orders</b><p>Try another customer name, phone or Order ID.</p></div>'}</section>${adminInfo?.username==='admin1'?`<section class="webhook-panel"><div><h2>Payment Webhook</h2><p>Gunakan key ini dalam Activepieces atau Make untuk auto-match bayaran.</p><span class="webhook-status ${adminInfo.paymentWebhookConfigured?'configured':''}">${adminInfo.paymentWebhookConfigured?'Configured':'Not configured'}</span></div><button id="generateWebhookKey">${adminInfo.paymentWebhookConfigured?'Regenerate Key':'Generate Key'}</button></section><section class="backup-panel"><div><h2>Data Backup</h2><p>Download salinan data supaya order tidak terkunci dalam satu platform.</p></div><button id="exportJson">Backup JSON</button><button id="exportCsv">Orders CSV</button></section><section class="permission-panel"><h2>Admin Permissions</h2><p>Admin 1 boleh kawal akses Admin 2 dan Admin 3.</p>${adminUsers.filter(a=>a.username!=='admin1').map(a=>`<article><header><b>${a.username}</b><button data-save-perms="${a.username}">Save</button></header>${['view_orders','create_order','mark_paid','approve_cash','edit_order','approve_production','cancel_order','open_whatsapp'].map(p=>`<label><input type="checkbox" data-perm-user="${a.username}" value="${p}" ${a.permissions.includes(p)?'checked':''}>${p.replaceAll('_',' ')}</label>`).join('')}</article>`).join('')}</section>`:''}</main>`;document.querySelector<HTMLButtonElement>('#adminCreateOrderBtn')?.addEventListener('click',adminCreateOrder);document.querySelector<HTMLButtonElement>('#adminLogout')!.onclick=()=>{adminSession='';adminInfo=null;sessionStorage.removeItem('admin_session');render()};document.querySelector<HTMLFormElement>('#adminSearchForm')!.onsubmit=e=>{e.preventDefault();adminSearch=String(new FormData(e.currentTarget).get('search')||'');selectedCustomerToken='';render()};document.querySelector<HTMLButtonElement>('#clearAdminSearch')?.addEventListener('click',()=>{adminSearch='';render()});document.querySelector<HTMLButtonElement>('#closeCustomerProfile')?.addEventListener('click',()=>{selectedCustomerToken='';render()});document.querySelectorAll<HTMLButtonElement>('[data-customer-token]').forEach(b=>b.onclick=()=>{selectedCustomerToken=b.dataset.customerToken!;render()});document.querySelectorAll<HTMLButtonElement>('[data-admin-tab]').forEach(b=>b.onclick=()=>{adminTab=b.dataset.adminTab!;render()});document.querySelectorAll<HTMLButtonElement>('[data-admin-action]').forEach(b=>b.onclick=()=>void adminAction(b.dataset.orderDb!,b.dataset.adminAction!));document.querySelectorAll<HTMLButtonElement>('[data-edit-order]').forEach(b=>b.onclick=()=>{const o=adminOrders.find(x=>x.dbId===b.dataset.editOrder);if(o)editAdminOrder(o)});document.querySelectorAll<HTMLButtonElement>('[data-view-order]').forEach(b=>b.onclick=()=>{selectedOrder=b.dataset.viewOrder!;page='order';currentOrder=null;void loadOrder(selectedOrder)});document.querySelectorAll<HTMLButtonElement>('[data-save-perms]').forEach(b=>b.onclick=()=>void saveAdminPermissions(b.dataset.savePerms!));document.querySelector<HTMLButtonElement>('#generateWebhookKey')?.addEventListener('click',()=>void generatePaymentWebhookKey());document.querySelector<HTMLButtonElement>('#exportJson')?.addEventListener('click',()=>void exportAdminData('json'));document.querySelector<HTMLButtonElement>('#exportCsv')?.addEventListener('click',()=>void exportAdminData('csv'))}
async function send(payload:unknown){const {data,error}=await supabase.rpc('icetak_create_order',{payload});if(error)throw new Error(error.message);return {order_id:data.order_id as string,order_token:data.order_token as string,customer_token:(data.customer_id as string)||'',confirm_token:undefined as string|undefined}}
async function submit(){if(!customer){customerForm();return}const normalizedPhone=normalizeMalaysiaPhone(customer.phone);if(!normalizedPhone){toast('Nombor WhatsApp Malaysia tidak sah');customerForm();return}customer.phone=normalizedPhone;if(ship!=='pickup'&&(!customer.address_line1||!customer.city||!customer.postcode||!customer.state)){toast('Lengkapkan alamat penghantaran');customerForm();return}if(!date){toast('Pilih Date Need dahulu');highlightDateNeed();return}const itemSummary=cart.map(i=>`<div class="review-order-item"><b>${i.qty}× ${i.title}</b><span>${i.size} • ${i.style}${i.customText?` • ${i.customText}`:''}</span><strong>${money(i.price*i.qty)}</strong></div>`).join('');const w=modal(`<button class="modal-x">×</button><h2>Review Order</h2><p>Semak semua maklumat sebelum order dihantar.</p><section class="review-order-summary"><div><span>Customer</span><b>${customer.name}</b></div><div><span>WhatsApp</span><b>${customer.phone}</b></div><div><span>Date Need</span><b>${date}</b></div><div><span>${ship==='pickup'?'Pickup':'Delivery'}</span><b>${ship==='pickup'?'Bandar Baru Pasir Puteh':customer.address_masked}</b></div><div><span>Courier</span><b>${D[ship].name}</b></div><div><span>Payment</span><b>${pay}</b></div>${itemSummary}<div class="review-order-total"><span>Total</span><b>${money(total())}</b></div></section><label class="whatsapp-consent"><input id="notifyWhatsapp" type="checkbox" checked><span><b>Terima notifikasi WhatsApp</b><small>Status bayaran, design, production dan penghantaran akan dihantar oleh DecoCake.my.</small></span></label><button id="confirmPlaceOrder" class="confirm">Confirm & Place Order</button><button id="backToCheckout" class="confirm secondary-confirm">Back to Edit</button><button id="cancelCheckoutReview" class="confirm secondary-confirm">Cancel Checkout</button>`);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#backToCheckout')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#cancelCheckoutReview')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#confirmPlaceOrder')!.onclick=()=>{const notifyWhatsapp=w.querySelector<HTMLInputElement>('#notifyWhatsapp')!.checked;w.remove();void createOrderNow(notifyWhatsapp)}}
async function createOrderNow(notifyWhatsapp=true){if(!customer){customerForm();return}const normalizedPhone=normalizeMalaysiaPhone(customer.phone);if(!normalizedPhone){toast('Nombor WhatsApp Malaysia tidak sah');customerForm();return}customer.phone=normalizedPhone;if(ship!=='pickup'&&(!customer.address_line1||!customer.city||!customer.postcode||!customer.state)){toast('Lengkapkan alamat penghantaran');customerForm();return}if(!date){toast('Pilih Date Need dahulu');highlightDateNeed();return}const btn=document.querySelector<HTMLButtonElement>('#wa')!;btn.disabled=true;btn.textContent='Creating…';try{const r=await send({customer_token:customerToken,customer,items:cart,date_need:date,delivery:ship,payment:pay,total:total(),consent:true,notify_whatsapp:notifyWhatsapp});setCustomerToken(r.customer_token);const lines=cart.map((i,n)=>`${n+1}. ${i.title}\n${i.process}\n${i.size}\n${i.style}\n${money(i.price)} × ${i.qty}`).join('\n\n');const confirmUrl=r.confirm_token?`${location.origin}${location.pathname}?confirm=${encodeURIComponent(r.confirm_token)}`:'',msg=r.confirm_token?`Hi ${customer.name}, sila semak dan sahkan order iCetak anda.\n\nOrder ID: ${r.order_id}\nDate Need: ${date}\nJumlah: ${money(total())}\nBayaran: Cash semasa pickup\n\nTekan link ini untuk sahkan order:\n${confirmUrl}\n\nOrder hanya masuk production selepas disahkan.`:`Hi iCetak, saya ingin membuat tempahan.\n\nOrder ID: ${r.order_id}\nDate Need: ${date}\n\n${lines}\n\nBayaran\n${pay}\n\nJumlah\n${money(total())}`;const waUrl=r.confirm_token?`https://wa.me/${customer.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`:`https://wa.me/${WA}?text=${encodeURIComponent(msg)}`;cart=[];save();date='';sessionStorage.removeItem('need_date');const confirmation=modal(`<button class="modal-x">×</button><h2>Order Created</h2><p>Order ID</p><strong class="order-confirm-id">${r.order_id}</strong><p>${r.confirm_token?'Order disimpan tetapi dikunci. Customer mesti confirm sebelum masuk production.':pay==='QR Pay'?'Order disimpan dalam To Pay sehingga bayaran disahkan.':'Order berjaya disimpan.'}</p>${r.confirm_token?`<a class="confirm wa-confirm" href="${waUrl}" target="_blank">Send Confirmation on WhatsApp</a><a class="confirm secondary-confirm" href="${confirmUrl}">Confirm Order Now</a>`:`<button id="payCreatedOrder" class="confirm wa-confirm">Pay Now</button>`}<button id="copyCreatedLink" class="confirm secondary-confirm">Copy Tracking Link</button><button id="viewCreated" class="confirm">View Order</button>`);confirmation.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>confirmation.remove();confirmation.querySelector<HTMLButtonElement>('#payCreatedOrder')?.addEventListener('click',()=>{confirmation.remove();selectedOrder=r.order_token;navigate('payment',{orderToken:selectedOrder});void loadPayment(selectedOrder)});confirmation.querySelector<HTMLButtonElement>('#copyCreatedLink')!.onclick=async()=>{await navigator.clipboard.writeText(singleOrderUrl(r.order_token));toast('Tracking link copied')};confirmation.querySelector<HTMLButtonElement>('#viewCreated')!.onclick=()=>{confirmation.remove();selectedOrder=r.order_token;currentOrder=null;navigate('order',{orderToken:selectedOrder});void loadOrder(selectedOrder)}}catch{toast('Order gagal disimpan');btn.disabled=false;btn.textContent='Place Order'}}
function ensurePaymentConnection(){if(paymentConnection)return paymentConnection;const conn=ws.connect();conn.onMessage(message=>{const payload=message?.payload;if(message?.type!=='entity.update'||payload?.entity_type!=='payment'||payload.entity_id!==paymentSubscriptionToken)return;const next=payload.data?.payment as PaymentInfo|undefined;if(!next)return;const firstMatch=paymentInfo?.status!=='matched'&&next.status==='matched';paymentInfo=next;if(page==='payment'){render();if(firstMatch)toast('Payment received ✅')}});paymentConnection=conn;return conn}
async function subscribePayment(token:string){const conn=ensurePaymentConnection();await conn.ready;if(!conn.connectionId)return;if(paymentSubscriptionToken&&paymentSubscriptionToken!==token)await api.post('/api/subscriptions/remove',{entity_type:'payment',entity_id:paymentSubscriptionToken,connection_id:conn.connectionId}).catch(()=>{});paymentSubscriptionToken=token;await api.post('/api/subscriptions',{entity_type:'payment',entity_id:token,connection_id:conn.connectionId})}
async function unsubscribePayment(){const conn=paymentConnection,token=paymentSubscriptionToken;paymentSubscriptionToken='';if(conn?.connectionId&&token)await api.post('/api/subscriptions/remove',{entity_type:'payment',entity_id:token,connection_id:conn.connectionId}).catch(()=>{})}
async function loadPayment(token:string){paymentLoading=true;paymentInfo=null;page='payment';render();try{const r=await api.post('/api/orders/'+encodeURIComponent(token)+'/payment-session',{});paymentInfo=r.data.payment as PaymentInfo;await subscribePayment(token)}catch{toast('Payment page gagal dimuatkan')}paymentLoading=false;render()}
function receiptBase64(file:File){return new Promise<string>((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(String(reader.result||'').split(',')[1]||'');reader.onerror=()=>reject(reader.error);reader.readAsDataURL(file)})}
function paymentPage(){clearInterval(paymentTimer);if(paymentLoading||!paymentInfo){root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Payment</h1></header><main class="payment-page"><section class="payment-panel"><h2>${paymentLoading?'Preparing secure amount…':'Payment unavailable'}</h2></section></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('order');return}const p=paymentInfo;if(p.status==='matched'){root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Payment</h1></header><main class="payment-page"><section class="payment-panel payment-success-hero"><div class="payment-success-icon">✓</div><h2>Payment Received</h2><strong>${money(p.expectedAmount)}</strong><p>Bayaran telah dipadankan secara automatik. Order anda sudah masuk ke proses seterusnya.</p><button id="viewPaidOrder" class="pay-now-btn">View Order Status</button></section></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>{void unsubscribePayment();goBack('order')};document.querySelector<HTMLButtonElement>('#viewPaidOrder')!.onclick=()=>{void unsubscribePayment();selectedOrder=p.orderToken;navigate('order',{orderToken:p.orderToken});void loadOrder(p.orderToken)};return}const remaining=Math.max(0,p.expiresAt-Date.now()),minutes=String(Math.floor(remaining/60000)).padStart(2,'0'),seconds=String(Math.floor((remaining%60000)/1000)).padStart(2,'0'),expired=remaining<=0;root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Pay Order</h1></header><main class="payment-page"><section class="payment-panel payment-hero"><small>Order ${p.orderId}</small><h2>Scan DuitNow QR</h2><div class="payment-countdown ${expired?'expired':''}"><span>${expired?'Session expired':'Amount reserved for'}</span><b id="paymentCountdown">${minutes}:${seconds}</b></div><div class="payment-live"><i></i> Live payment detection active</div><img class="payment-qr" src="https://t3747262.p.clickup-attachments.com/t3747262/836016e0-e613-447b-b61a-291fddd3f83d_large.png" alt="DecoCake.my DuitNow QR"><p>Masukkan jumlah ini tepat semasa membuat bayaran:</p><button id="copyPaymentAmount" class="payment-amount"><small>Exact Amount</small><strong>${money(p.expectedAmount)}</strong><span>Tap to copy</span></button>${p.discount>0?`<div class="payment-discount">Discount matching amount: ${money(p.discount)}</div>`:''}<small>Jangan round up atau ubah sen. Sistem padankan bayaran berdasarkan jumlah ini.</small>${expired?'<button id="refreshPaymentSession" class="pay-now-btn">Generate New 10-Minute Amount</button>':''}</section><section class="payment-panel"><h3>Bukti Bayaran</h3><p>Selepas bayar, snap atau upload resit JPG, PNG atau PDF.</p>${p.status==='matched'?`<div class="payment-approved"><b>✅ Payment Confirmed</b><span>Bayaran telah disahkan dan order sedang diproses.</span>${p.receiptUrl?`<a href="${p.receiptUrl}" target="_blank">View receipt</a>`:''}</div>`:p.receiptUrl?`<div class="payment-pending"><b>⏳ Pending Admin Approval</b><span>Bukti bayaran telah diterima. Admin sedang menyemak bayaran anda.</span><a class="receipt-ready" href="${p.receiptUrl}" target="_blank">View uploaded receipt</a><small>Tak perlu upload semula. Status akan berubah selepas admin mengesahkan bayaran.</small></div>`:`<label class="receipt-upload">Choose Receipt<input id="receiptFile" type="file" accept="image/jpeg,image/png,application/pdf"></label><button id="uploadReceipt" class="pay-now-btn">Upload Payment Receipt</button>`}</section><section class="payment-panel gateway-later"><h3>Payment Gateway</h3><p>Online payment link akan ditambah kemudian.</p><button disabled>Coming Soon</button></section></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('order');document.querySelector<HTMLButtonElement>('#copyPaymentAmount')!.onclick=async()=>{await navigator.clipboard.writeText(p.expectedAmount.toFixed(2));toast('Amount copied')};document.querySelector<HTMLButtonElement>('#refreshPaymentSession')?.addEventListener('click',()=>void loadPayment(selectedOrder));document.querySelector<HTMLButtonElement>('#uploadReceipt')?.addEventListener('click',async()=>{const input=document.querySelector<HTMLInputElement>('#receiptFile')!,file=input.files?.[0];if(!file){toast('Pilih receipt dahulu');return}if(file.size>5*1024*1024){toast('Receipt maksimum 5MB');return}const button=document.querySelector<HTMLButtonElement>('#uploadReceipt')!;button.disabled=true;button.textContent='Uploading…';try{const data=await receiptBase64(file),r=await api.post('/api/orders/'+encodeURIComponent(selectedOrder)+'/payment-receipt',{data,mime_type:file.type,file_name:file.name});paymentInfo=r.data.payment;toast('Receipt uploaded');render()}catch{toast('Upload receipt gagal');button.disabled=false;button.textContent='Upload Payment Receipt'}});if(!expired)paymentTimer=window.setInterval(()=>{if(page!=='payment'){clearInterval(paymentTimer);return}const left=Math.max(0,p.expiresAt-Date.now()),el=document.querySelector<HTMLElement>('#paymentCountdown');if(el)el.textContent=`${String(Math.floor(left/60000)).padStart(2,'0')}:${String(Math.floor((left%60000)/1000)).padStart(2,'0')}`;if(left<=0){clearInterval(paymentTimer);render()}},1000)}
async function loadConfirmation(token:string){confirmationLoading=true;page='confirm';render();try{const r=await api.get('/api/order-confirmations/'+encodeURIComponent(token));confirmationOrder=r.data.order as OrderRecord}catch{confirmationOrder=null}confirmationLoading=false;render()}
function confirmPage(){if(confirmationLoading){root.innerHTML='<main class="confirm-page"><section class="confirm-card"><h2>Loading order…</h2></section></main>';return}if(!confirmationOrder){root.innerHTML='<main class="confirm-page"><section class="confirm-card"><h2>Link tidak sah</h2><p>Confirmation link tidak dijumpai atau sudah tamat.</p></section></main>';return}const o=confirmationOrder;root.innerHTML=`<main class="confirm-page"><section class="confirm-card"><div class="confirm-icon">✓</div><small>iCetak Order Confirmation</small><h1>${o.id}</h1><p>Date Need: <b>${o.dateNeed}</b></p><div class="confirm-items">${o.items.map(i=>`<span>${i.qty}× ${i.title} — ${money(i.price*i.qty)}</span>`).join('')}</div><strong class="confirm-total">${money(o.total)}</strong>${o.customerConfirmed?'<div class="confirmed-banner">✅ Order ini sudah disahkan.</div>':'<><p>Dengan menekan butang di bawah, customer mengesahkan detail order betul dan iCetak boleh mula proses production.</p><button id="confirmCashOrder" class="confirm">Ya, Order Betul — Confirm</button></>'}</section></main>`;document.querySelector<HTMLButtonElement>('#confirmCashOrder')?.addEventListener('click',async()=>{const b=document.querySelector<HTMLButtonElement>('#confirmCashOrder')!;b.disabled=true;b.textContent='Confirming…';try{await api.post('/api/order-confirmations/'+encodeURIComponent(confirmationToken),{});toast('Order confirmed');await loadConfirmation(confirmationToken)}catch{toast('Confirmation gagal');b.disabled=false;b.textContent='Ya, Order Betul — Confirm'}})}
function render(){page==='catalog'?catalog():page==='detail'?detail():page==='review'?review():page==='history'?historyPage():page==='payment'?paymentPage():page==='admin'?adminPage():page==='access'?accessPage():page==='confirm'?confirmPage():orderPage()}
window.addEventListener('beforeinstallprompt',event=>{event.preventDefault();deferredInstallPrompt=event as InstallPromptEvent;if(page==='catalog')render()});window.addEventListener('appinstalled',()=>{deferredInstallPrompt=null;isStandalone=true;toast('DecoCake.my installed')});window.addEventListener('popstate',event=>{const state=event.state as {page?:Page;product?:K;orderToken?:string}|null;if(!state?.page){if(page==='payment')void unsubscribePayment();page='catalog';render();return}if(page==='payment'&&state.page!=='payment')void unsubscribePayment();page=state.page;if(state.product)product=state.product;if(state.orderToken){selectedOrder=state.orderToken;if(page==='order'){currentOrder=null;void loadOrder(selectedOrder);return}}render()});if('serviceWorker' in navigator)window.addEventListener('load',()=>{void navigator.serviceWorker.register('/sw.js',{scope:'/'}).catch(()=>navigator.serviceWorker.register('./sw.js'))});
async function bootstrap(){history.replaceState({page,product,orderToken:selectedOrder},'',location.href);if(customerToken)await loadCustomerProfile();const params=new URLSearchParams(location.search),orderToken=params.get('order'),confirmToken=params.get('confirm');if(orderToken){selectedOrder=orderToken;page='order';currentOrder=null;await loadOrder(orderToken);return}if(confirmToken){confirmationToken=confirmToken;await loadConfirmation(confirmToken);return}const loginToken=params.get('login');if(loginToken){root.innerHTML='<main class="history-page"><div class="empty-history"><b>Signing in…</b><p>Checking temporary WhatsApp login link.</p></div></main>';try{const r=await api.post('/api/login/exchange',{login_token:loginToken});setCustomerToken(r.data.customer_token);page='history';await loadHistory();return}catch{const u=new URL(location.href);u.searchParams.delete('login');history.replaceState({},'',u);toast('Login link tidak sah atau telah tamat tempoh')}}render()}
void bootstrap();